import torch
import torch.nn as nn

# Plain deep network (chaotic loss surface)
class PlainNet(nn.Module):
    def __init__(self, depth=20):
        super().__init__()
        layers = []
        for _ in range(depth):
            layers += [nn.Linear(64, 64), nn.ReLU()]
        layers += [nn.Linear(64, 10)]
        self.net = nn.Sequential(*layers)

    def forward(self, x):
        return self.net(x)

# ResNet-style (smooth loss surface via skip connections)
class ResBlock(nn.Module):
    def __init__(self, dim=64):
        super().__init__()
        self.fc1 = nn.Linear(dim, dim)
        self.fc2 = nn.Linear(dim, dim)
        self.norm = nn.LayerNorm(dim)

    def forward(self, x):
        return x + self.fc2(torch.relu(self.fc1(self.norm(x))))  # residual!

class ResNet(nn.Module):
    def __init__(self, depth=20):
        super().__init__()
        self.blocks = nn.ModuleList([ResBlock() for _ in range(depth)])
        self.head = nn.Linear(64, 10)

    def forward(self, x):
        for block in self.blocks:
            x = block(x)
        return self.head(x)

# Loss surface comparison
X = torch.randn(256, 64);  y = torch.randint(0, 10, (256,))
plain_model = PlainNet(depth=20)
res_model   = ResNet(depth=20)

def measure_surface_roughness(model, loss_fn, X, y, n_trials=10):
    """Estimate roughness by measuring loss variation over random perturbations."""
    losses = []
    params = [p.data.clone() for p in model.parameters()]
    for _ in range(n_trials):
        # Add random noise to params
        for p in model.parameters():
            p.data += 0.001 * torch.randn_like(p)
        with torch.no_grad():
            losses.append(loss_fn(model(X), y).item())
        # Restore
