# Sharpness-Aware Minimization (SAM) — seeks flat minima explicitly
# pip install sam-pytorch

class SAM(torch.optim.Optimizer):
    """Simplified SAM: finds parameters where loss is flat in all directions."""
    def __init__(self, params, base_optimizer_cls, rho=0.05, **kwargs):
        self.base_optimizer = base_optimizer_cls(params, **kwargs)
        self.rho = rho
        super().__init__(params, dict(rho=rho))

    @torch.no_grad()
    def first_step(self, zero_grad=False):
        """Perturb weights toward the steepest ascent direction."""
        grad_norm = self._grad_norm()
        for group in self.param_groups:
            scale = self.rho / (grad_norm + 1e-12)
            for p in group["params"]:
                if p.grad is None: continue
                self.state[p]["old_p"] = p.data.clone()
                e_w = p.grad * scale   # perturbation direction
                p.add_(e_w)            # move to worst-case neighbour
        if zero_grad: self.zero_grad()

    @torch.no_grad()
    def second_step(self, zero_grad=False):
        """Restore weights and update using worst-neighbour gradient."""
        for group in self.param_groups:
            for p in group["params"]:
                if p.grad is None: continue
                p.data = self.state[p]["old_p"]
        self.base_optimizer.step()
        if zero_grad: self.zero_grad()

    def _grad_norm(self):
        norms = [p.grad.norm(2) for g in self.param_groups for p in g["params"]
                 if p.grad is not None]
        return torch.stack(norms).norm(2)

# Training loop with SAM
